// Helper to persist overlay mapping
async function saveOverlayResponseTabMap(token, data) {
  try {
    const res = await lpApi.storage.local.get(OVERLAY_RESPONSE_TAB_STORAGE_KEY);
    const map = res[OVERLAY_RESPONSE_TAB_STORAGE_KEY] || {};
    if (data) {
      map[token] = data;
    } else {
      delete map[token];
    }
    await lpApi.storage.local.set({ [OVERLAY_RESPONSE_TAB_STORAGE_KEY]: map });
  } catch (err) {}
}

async function getOverlayResponseTabMap(token) {
  try {
    const res = await lpApi.storage.local.get(OVERLAY_RESPONSE_TAB_STORAGE_KEY);
    const map = res[OVERLAY_RESPONSE_TAB_STORAGE_KEY] || {};
    return token ? map[token] : map;
  } catch (err) {
    return token ? null : {};
  }
}

