        button.style.background = "rgba(255, 210, 74, 0.16)";
        button.style.border = "1px solid rgba(255, 210, 74, 0.48)";
        button.style.color = "#ffd24a";
        button.style.boxShadow = "inset 0 0 0 1px rgba(255, 210, 74, 0.08)";
